import Redis from 'ioredis';
import Opossum from 'opossum';
import { randomUUID } from 'crypto';

/**
 * Production-ready Redis cache and locking client for inventory reconciliation.
 * Implements circuit breaking, distributed locking with TTL, and structured inventory access.
 */
export class ReconciliationCacheManager {
  private client: Redis;
  private breaker: Opossum;
  private readonly lockPrefix = 'reconciliation:lock:';
  private readonly inventoryPrefix = 'reconciliation:inventory:';

  constructor(redisUrl: string = process.env.REDIS_URL || 'redis://localhost:6379') {
    this.client = new Redis(redisUrl, {
      retryStrategy: (times) => Math.min(times * 1000, 30000),
      maxRetriesPerRequest: 3,
      enableReadyCheck: true,
    });

    // Circuit breaker for Redis operations
    this.breaker = new Opossum(async (cmd: string, ...args: any[]) => {
      return (this.client as any)[cmd](...args);
    }, {
      timeout: 3000,
      errorThresholdPercentage: 50,
      resetTimeout: 30000,
    });
  }

  /**
   * Acquires a distributed lock for a specific SKU range.
   */
  async lockSkuRange(skuRange: string, ttlSeconds: number = 60): Promise<boolean> {
    const key = `${this.lockPrefix}${skuRange}`;
    const requestId = randomUUID();
    const result = await this.breaker.fire('set', key, requestId, 'EX', ttlSeconds, 'NX');
    return result === 'OK';
  }

  /**
   * Releases a distributed lock.
   */
  async releaseSkuRange(skuRange: string): Promise<void> {
    const key = `${this.lockPrefix}${skuRange}`;
    await this.breaker.fire('del', key);
  }

  /**
   * Sets product inventory state in cache.
   */
  async setInventoryState(productId: string, state: Record<string, any>, ttlSeconds: number = 3600): Promise<void> {
    const key = `${this.inventoryPrefix}${productId}`;
    await this.breaker.fire('set', key, JSON.stringify(state), 'EX', ttlSeconds);
  }

  /**
   * Retrieves product inventory state from cache.
   */
  async getInventoryState(productId: string): Promise<Record<string, any> | null> {
    const key = `${this.inventoryPrefix}${productId}`;
    const data = await this.breaker.fire('get', key);
    return data ? JSON.parse(data as string) : null;
  }

  /**
   * Graceful shutdown of the Redis connection.
   */
  async disconnect(): Promise<void> {
    await this.client.quit();
  }
}
